mapper.select:
SELECT ID, QUIZ_START_AT, USER_ID, QUIZ_ID, QUIZ_START_COMPLETED_COUNT, QUIZ_START_CORRECT_COUNT
FROM TBL_QUIZ_START
WHERE USER_ID = #{userId}
  AND QUIZ_ID = #{quizId}

mapper.update:
UPDATE TBL_QUIZ_START
SET QUIZ_START_AT = CURRENT_TIMESTAMP,
    QUIZ_START_COMPLETED_COUNT = 0,
    QUIZ_START_CORRECT_COUNT = 0
WHERE USER_ID = #{userId}
  AND QUIZ_ID = #{quizId}

UPDATE TBL_QUIZ_START
SET QUIZ_START_COMPLETED_COUNT = QUIZ_START_COMPLETED_COUNT + 1,
    QUIZ_START_CORRECT_COUNT = QUIZ_START_CORRECT_COUNT + #{isCorrect}
WHERE USER_ID = #{userId}
  AND QUIZ_ID = #{quizId}
  AND QUIZ_START_COMPLETED_COUNT < #{totalCount}
